const { LLMAgent } = require('llm-agent');

// Create a new LLM agent instance
const llmAgent = new LLMAgent();

// Set the language model to use
llmAgent.setLanguageModel('en');

// Start the LLM agent
llmAgent.start();

// Define a function to handle user input
function handleUserInput(input) {
  // Send the input to the AI model
  const output = llmAgent.processInput(input);
  
  // Execute the generated code
  eval(output);
}

// Start listening for user input
const stdin = process.openStdin();
stdin.addListener('data', handleUserInput);